package models

import (
	"errors"
	"fmt"
)

// ErrInvalid is the sentinel wrapped by every validation failure.
var ErrInvalid = errors.New("invalid")

// Order is a domain entity with a lifecycle status.
type Order struct {
	ID     string `json:"id"`
	Status string `json:"status"`
}

// Event is a SEPARATE domain type in the SAME package — a package often holds
// more than one type; define EVERY type the spec lists, not just the first.
type Event struct {
	Type    string `json:"type"`
	OrderID string `json:"order_id"`
}

// Validate reports whether the order is well-formed, wrapping ErrInvalid.
func (o Order) Validate() error {
	if o.ID == "" {
		return fmt.Errorf("%w: id is required", ErrInvalid)
	}
	if o.Status != "open" && o.Status != "shipped" && o.Status != "closed" {
		return fmt.Errorf("%w: bad status %q", ErrInvalid, o.Status)
	}
	return nil
}
